import{_ as t,o as r,c as s,j as e,a as n}from"./chunks/framework.Nkqvsbxc.js";const m=JSON.parse('{"title":"慈雲懺主淨土文","description":"","frontmatter":{},"headers":[],"relativePath":"scriptures/小净土文.md","filePath":"scriptures/小净土文.md"}'),l={name:"scriptures/小净土文.md"};function o(c,a,p,i,d,u){return r(),s("div",null,[...a[0]||(a[0]=[e("h1",{id:"慈雲懺主淨土文",tabindex:"-1"},[n("慈雲懺主淨土文 "),e("a",{class:"header-anchor",href:"#慈雲懺主淨土文","aria-label":'Permalink to "慈雲懺主淨土文"'},"​")],-1),e("p",null,[e("em",null,"（又稱小淨土文）")],-1),e("p",null,"一心皈命，極樂世界，阿彌陀佛。願以淨光照我，慈誓攝我。我今正念，稱如來名，為菩提道，求生淨土。佛昔本誓，若有眾生，欲生我國，至心信樂，乃至十念，若不生者，不取正覺。",-1),e("p",null,"以此念佛因緣，得入如來大誓海中。承佛慈力，眾罪消滅，善根增長。若臨命終，自知時至，身無病苦，心不貪戀，意不顛倒，如入禪定。佛及聖眾，手執金臺，來迎接我。於一念頃，生極樂國。",-1),e("p",null,"花開見佛，即聞佛乘，頓開佛慧，廣度眾生，滿菩提願。十方三世一切佛，一切菩薩摩訶薩，摩訶般若波羅蜜。",-1)])])}const f=t(l,[["render",o]]);export{m as __pageData,f as default};
